            return parse_number()

    def truncate_toward_zero(a: int, b: int) -> int:
        # Python's // floors; adjust for truncation toward zero.
        q = a // b
        r = a % b
        if (a < 0) ^ (b < 0) and r != 0:
            q += 1
        return q

