def median(a, b):
    # Ensure the first list is the shorter one for O(log(min(len(a), len(b))))
    if len(a) > len(b):
        return median(b, a)

    n, m = len(a), len(b)
    total = n + m

    def kth(k):  # k is 1‑based
        A, B = a, b
        while True:
            if not A:
                return B[k - 1]
            if not B:
                return A[k - 1]
            if k == 1:
                return min(A[0], B[0])

            i = min(len(A), k // 2)
            j = min(len(B), k // 2)

            if A[i - 1] < B[j - 1]:
                A = A[i:]
                k -= i
            else:
                B = B[j:]
                k -= j

    if total % 2 == 1:
        return float(kth(total // 2 + 1))
    else:
        left = kth(total // 2)
        right = kth(total // 2 + 1)
        return (left + right) / 2.0

